PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "username" varchar, "asgl_id" varchar, "mobile_phone" varchar, "avatar" varchar, "department_name" varchar);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "fork_lifts" ("id" integer primary key autoincrement not null, "name" varchar not null, "brand" varchar not null, "serial_number" varchar not null, "total_working_hours" numeric not null default '0', "status" varchar check ("status" in ('active', 'inactive', 'maintenance')) not null default 'active', "created_at" datetime, "updated_at" datetime, "dvql" varchar);
CREATE TABLE IF NOT EXISTS "batteries" ("id" integer primary key autoincrement not null, "serial_number" varchar not null, "code" varchar not null, "type" varchar, "capacity" varchar, "voltage" varchar, "size" varchar, "used_at" date, "status" varchar check ("status" in ('standby', 'in_use', 'charging', 'maintenance')) not null default 'standby', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "battery_usages" ("id" integer primary key autoincrement not null, "battery_id" integer not null, "fork_lift_id" integer not null, "charger_bar" integer, "screen_bar" integer, "hour_initial" numeric, "installed_at" datetime, "hour_out" numeric, "removed_at" datetime, "working_hours" numeric, "installed_by" integer, "removed_by" integer, "status" varchar check ("status" in ('running', 'finished')) not null default 'running', "created_at" datetime, "updated_at" datetime, foreign key("battery_id") references "batteries"("id") on delete cascade, foreign key("fork_lift_id") references "fork_lifts"("id") on delete cascade, foreign key("installed_by") references "users"("id") on delete set null, foreign key("removed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "battery_chargers" ("id" integer primary key autoincrement not null, "code" varchar not null, "location" varchar, "created_at" datetime, "updated_at" datetime);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "batteries_serial_number_unique" on "batteries" ("serial_number");
CREATE UNIQUE INDEX "batteries_code_unique" on "batteries" ("code");
CREATE UNIQUE INDEX "battery_chargers_code_unique" on "battery_chargers" ("code");
COMMIT;
